CREATE TABLE partsupp AS SELECT * FROM read_csv('data/SF-1/partsupp.tbl', delim='|', header=false, columns={'ps_partkey':'INTEGER','ps_suppkey':'INTEGER','ps_availqty':'INTEGER','ps_supplycost':'DECIMAL(15,2)','ps_comment':'VARCHAR','dummy':'VARCHAR'});
CREATE TABLE supplier AS SELECT * FROM read_csv('data/SF-1/supplier.tbl', delim='|', header=false, columns={'s_suppkey':'INTEGER','s_name':'VARCHAR','s_address':'VARCHAR','s_nationkey':'INTEGER','s_phone':'VARCHAR','s_acctbal':'DECIMAL(15,2)','s_comment':'VARCHAR','dummy':'VARCHAR'});
CREATE TABLE nation AS SELECT * FROM read_csv('data/SF-1/nation.tbl', delim='|', header=false, columns={'n_nationkey':'INTEGER','n_name':'VARCHAR','n_regionkey':'INTEGER','n_comment':'VARCHAR','dummy':'VARCHAR'});
SELECT ps_partkey, CAST(SUM(ps_supplycost * ps_availqty) AS DOUBLE) AS value FROM partsupp, supplier, nation WHERE ps_suppkey = s_suppkey AND s_nationkey = n_nationkey AND n_name = 'GERMANY' GROUP BY ps_partkey HAVING SUM(ps_supplycost * ps_availqty) > (SELECT SUM(ps_supplycost * ps_availqty) * 0.0001 FROM partsupp, supplier, nation WHERE ps_suppkey = s_suppkey AND s_nationkey = n_nationkey AND n_name = 'GERMANY') ORDER BY value DESC LIMIT 5;
SELECT COUNT(*) AS total_qualifying FROM (SELECT ps_partkey FROM partsupp, supplier, nation WHERE ps_suppkey = s_suppkey AND s_nationkey = n_nationkey AND n_name = 'GERMANY' GROUP BY ps_partkey HAVING SUM(ps_supplycost * ps_availqty) > (SELECT SUM(ps_supplycost * ps_availqty) * 0.0001 FROM partsupp, supplier, nation WHERE ps_suppkey = s_suppkey AND s_nationkey = n_nationkey AND n_name = 'GERMANY'));
